    int T, N, M, i, j, k, x, y, z, count, min_count;
    int **grid, **visited;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &M);
        grid = (int **)malloc(N * sizeof(int *));
        visited = (int **)malloc(N * sizeof(int *));
        for (i = 0; i < N; i++) {
            grid[i] = (int *)malloc(M * sizeof(int));
            visited[i] = (int *)malloc(M * sizeof(int));
            for (j = 0; j < M; j++) {
                scanf("%d", &grid[i][j]);
                visited[i][j] = 0;
            }
        }
        min_count = INF;
        for (i = 0; i < N; i++) {
            for (j = 0; j < M; j++) {
                count = 0;
                for (x = 0; x < N; x++) {
                    for (y = 0; y < M; y++) {
                        if (grid[x][y] <= grid[i][j]) {
                            count++;
                        }
                    }
                }
                if (count < min_count) {
                    min_count = count;
                }
            }
        }
        printf("%d\n", min_count);
        for (i = 0; i < N; i++) {
            free(grid[i]);
            free(visited[i]);
        }
        free(grid);
        free(visited);
    }
    return 0;
}

